      pax: number;
      share: number;
      routes: Array<(typeof overview.countryRouteContribution)[number]>;
    }>();
    for (const row of overview.countryRouteContribution) {
      const current = groups.get(row.country) ?? {
        country: row.country,
        flights: 0,
        pax: 0,
        share: 0,
        routes: [],
